	{
		UE_LOG_LOGIN_QUEUE(Warning, TEXT("Identity interface is not valid."));
		return;
	}

	IdentityInterface->AccelByteOnLoginQueueCancelCompleteDelegates->AddUObject(this, &ThisClass::OnLoginQueueCancelCompleted);
