UStoreItemDataObject* UEntitlementsEssentialsSubsystem::GetItemEntitlement(
	const FUniqueNetIdPtr UserId,
	const FUniqueOfferId OfferId) const
{
	if (!UserId) 
	{
		return nullptr;
	}

	UStoreItemDataObject* Item = nullptr;
