bool UPartyOnlineSession::IsInParty(const FUniqueNetIdPtr UserId)
{
	if (!UserId)
	{
		return false;
	}

	const TPartyMemberArray Members = GetPartyMembers();
	for (const auto& Member : Members)
	{
		if (!Member.Get().IsValid())
		{
			continue;
		}

		if (Member.Get() == UserId.ToSharedRef().Get())
		{
			return true;
		}
	}

	return false;
}

