	if (UStartupSubsystem* StartupSubsystem = GetWorld()->GetGameInstance()->GetSubsystem<UStartupSubsystem>())
	{
		StartupSubsystem->QueryUserInfo(
			0,
			TPartyMemberArray{ RejecterABId },
